data <- read.csv("data/synthetic_state_mutation_cases.csv", stringsAsFactors = FALSE)
data$state_quality <- 100 * (0.12*data$state_visibility + 0.12*data$mutation_control + 0.10*data$aliasing_risk_control + 0.10*data$side_effect_boundaries + 0.10*data$lifecycle_clarity + 0.10*data$concurrency_safety + 0.10*data$reproducibility_support + 0.10*data$auditability + 0.08*data$rollback_support + 0.08*data$governance_readiness)
data$mutation_risk <- 100 * rowMeans(1 - data[, c("state_visibility","mutation_control","aliasing_risk_control","side_effect_boundaries","lifecycle_clarity","concurrency_safety","reproducibility_support","auditability")])
dir.create("outputs/tables", recursive=TRUE, showWarnings=FALSE)
dir.create("outputs/figures", recursive=TRUE, showWarnings=FALSE)
write.csv(data, "outputs/tables/r_state_mutation_summary.csv", row.names=FALSE)
png("outputs/figures/r_state_quality_vs_mutation_risk.png", width=1400, height=800)
m <- rbind(data$state_quality, data$mutation_risk); colnames(m) <- data$case_name; rownames(m) <- c("State quality", "Mutation risk")
barplot(m, beside=TRUE, las=2, ylim=c(0,100), ylab="Score", main="State Quality vs. Mutation Risk")
legend("topleft", legend=rownames(m), pch=15, bty="n"); grid(); dev.off()
print(data)
